# For each example, for each geometric transform, check if a consistent color mapping exists

import numpy as np

def check_transform(inp, out, transform_name, transform_fn):
    """Check if a consistent color mapping exists under the given geometric transform"""
    transformed = transform_fn(inp)
    if transformed.shape != out.shape:
        return None

    # Find color mapping
    mapping = {}
    for r in range(out.shape[0]):
        for c in range(out.shape[1]):
            src = int(transformed[r][c])
            dst = int(out[r][c])
            if src in mapping:
                if mapping[src] != dst:
                    return None  # Inconsistent
            else:
                mapping[src] = dst
    return mapping

transforms = {
    'identity': lambda x: x,
    'transpose': lambda x: x.T,
    'rot90cw': lambda x: np.rot90(x, -1),
    'rot90ccw': lambda x: np.rot90(x, 1),
    'rot180': lambda x: np.rot90(x, 2),
    'flipud': lambda x: np.flipud(x),
    'fliplr': lambda x: np.fliplr(x),
    'transpose_flipud': lambda x: np.flipud(x.T),
    'transpose_fliplr': lambda x: np.fliplr(x.T),
}

for i, s in enumerate(train_samples):
    inp = np.array(s['input'])
    out = np.array(s['output'])
    print(f"\n=== Example {i}: {inp.shape} -> {out.shape} ===")

    for name, fn in transforms.items():
        mapping = check_transform(inp, out, name, fn)
        if mapping is not None:
            print(f"  {name}: {mapping}")

