# Better approach: identify T-crosses, determine source region, clean
# Step 1: Find T-crosses
# Step 2: For each cross, determine source region color from surrounding context
# Step 3: Replace cross cells with source region color
# Step 4: Handle remaining small markers (9-patterns etc.)

def find_t_crosses(grid):
    """Find all T-shaped patterns of 1s with optional non-1 center"""
    H, W = len(grid), len(grid[0])
    g = [[grid[r][c] for c in range(W)] for r in range(H)]

    crosses = []

    # T with vertical bar + right arm
    for r in range(1, H-1):
        for c in range(W-1):
            up, center, down, right = g[r-1][c], g[r][c], g[r+1][c], g[r][c+1]
            if up == 1 and down == 1 and right == 1:
                cells = [(r-1,c), (r,c), (r+1,c), (r,c+1)]
                center_color = center if center != 1 else None
                crosses.append({
                    'cells': cells,
                    'center': (r,c),
                    'center_color': center_color,
                    'direction': 'RIGHT'
                })

    # T with vertical bar + left arm
    for r in range(1, H-1):
        for c in range(1, W):
            up, center, down, left = g[r-1][c], g[r][c], g[r+1][c], g[r][c-1]
            if up == 1 and down == 1 and left == 1:
                cells = [(r-1,c), (r,c), (r+1,c), (r,c-1)]
                center_color = center if center != 1 else None
                crosses.append({
                    'cells': cells,
                    'center': (r,c),
                    'center_color': center_color,
                    'direction': 'LEFT'
                })

    # T with horizontal bar + down arm
    for r in range(H-1):
        for c in range(1, W-1):
            left, center, right, down = g[r][c-1], g[r][c], g[r][c+1], g[r+1][c]
            if left == 1 and right == 1 and down == 1:
                cells = [(r,c-1), (r,c), (r,c+1), (r+1,c)]
                center_color = center if center != 1 else None
                crosses.append({
                    'cells': cells,
                    'center': (r,c),
                    'center_color': center_color,
                    'direction': 'DOWN'
                })

    # T with horizontal bar + up arm
    for r in range(1, H):
        for c in range(1, W-1):
            left, center, right, up = g[r][c-1], g[r][c], g[r][c+1], g[r-1][c]
            if left == 1 and right == 1 and up == 1:
                cells = [(r,c-1), (r,c), (r,c+1), (r-1,c)]
                center_color = center if center != 1 else None
                crosses.append({
                    'cells': cells,
                    'center': (r,c),
                    'center_color': center_color,
                    'direction': 'UP'
                })

    return crosses

# For each example, find crosses and see how many 1-cells they cover
for i, s in enumerate(train_samples):
    inp = np.array(s['input'])
    ones = np.argwhere(inp == 1)
    total_ones = len(ones)

    crosses = find_t_crosses(s['input'])

    print(f"\n=== Example {i} ===")
    print(f"  Total 1s: {total_ones}")
    print(f"  Crosses found: {len(crosses)}")

    # Filter to non-overlapping crosses that cover all 1s
    # For each cross, the 1-cells are: all cells minus center (if center != 1)
    all_cross_cells = set()
    for cross in crosses:
        one_cells = set()
        for r, c in cross['cells']:
            if inp[r,c] == 1:
                one_cells.add((r,c))
        all_cross_cells.update(one_cells)

    one_set = set(map(tuple, ones.tolist()))
    uncovered = one_set - all_cross_cells
    print(f"  Covered 1s: {len(all_cross_cells)}, Uncovered: {len(uncovered)}")
    if uncovered:
        print(f"  Uncovered 1s at: {sorted(uncovered)}")

    for j, cross in enumerate(crosses):
        print(f"  Cross {j}: center={cross['center']}, dir={cross['direction']}, center_color={cross['center_color']}")

