# Find non-overlapping set of crosses that covers all 1s
from itertools import combinations

def find_non_overlapping_crosses(grid, crosses):
    """Find a set of non-overlapping crosses that covers all 1-cells"""
    inp = np.array(grid)
    one_cells = set(map(tuple, np.argwhere(inp == 1).tolist()))

    # For each cross, get the set of 1-cells it covers
    cross_ones = []
    for cross in crosses:
        ones_in_cross = set()
        for r, c in cross['cells']:
            if inp[r, c] == 1:
                ones_in_cross.add((r, c))
        cross_ones.append(ones_in_cross)

    # Try to find a subset that exactly partitions one_cells
    n = len(crosses)
    for size in range(1, n+1):
        for combo in combinations(range(n), size):
            covered = set()
            overlap = False
            for idx in combo:
                if covered & cross_ones[idx]:
                    overlap = True
                    break
                covered |= cross_ones[idx]
            if not overlap and covered == one_cells:
                return [crosses[idx] for idx in combo]
    return None

for i, s in enumerate(train_samples):
    crosses = find_t_crosses(s['input'])
    valid = find_non_overlapping_crosses(s['input'], crosses)

    print(f"\n=== Example {i} ===")
    if valid:
        print(f"  Found {len(valid)} non-overlapping crosses:")
        for cross in valid:
            print(f"    center={cross['center']}, dir={cross['direction']}, "
                  f"center_color={cross['center_color']}, cells={cross['cells']}")
    else:
        print("  No valid partition found!")

