                                    'center': (r,c), 'center_color': center if center != 1 else None,
                                    'direction': 'UP'})
        return crosses

    def find_nonoverlap(grid, crosses):
        inp = np.array(grid)
        one_cells = set(map(tuple, np.argwhere(inp == 1).tolist()))
        if not one_cells:
            return []
        cross_ones = []
        for cr in crosses:
            ones = set((r,c) for r,c in cr['cells'] if inp[r,c] == 1)
            cross_ones.append(ones)
        n = len(crosses)
        for size in range(1, n+1):
            for combo in combinations(range(n), size):
                covered = set()
                ok = True
                for idx in combo:
                    if covered & cross_ones[idx]:
                        ok = False; break
                    covered |= cross_ones[idx]
                if ok and covered == one_cells:
                    return [crosses[idx] for idx in combo]
        return []

