        d = cross['direction']
        dr, dc = {'RIGHT':(0,1),'LEFT':(0,-1),'DOWN':(1,0),'UP':(-1,0)}[d]

        nr, nc = r + 2*dr, c + 2*dc
        target = None
        while 0 <= nr < H and 0 <= nc < W:
            tc = comp_map[nr, nc]
            if tc != src_comp:
                target = tc; break
            nr += dr; nc += dc

        if target is not None:
            comp_new[target] = sent

    # Build output
    output = np.zeros((H, W), dtype=int)
    for r in range(H):
        for c in range(W):
            output[r, c] = comp_new[comp_map[r, c]]

    # Geometric transform
    if H != W:
        if l_rotation == 'ccw':
            return np.rot90(output, 1).tolist()
        elif l_rotation == 'cw':
            return np.rot90(output, -1).tolist()
        else:
            return [np.rot90(output, 1).tolist(), np.rot90(output, -1).tolist()]
