            for r, c in cross['cells']:
                if inp[r,c] == 1:
                    ones_in.add((r,c))
            cross_ones.append(ones_in)

        n = len(crosses)
        for size in range(1, n+1):
            for combo in combinations(range(n), size):
                covered = set()
                overlap = False
                for idx in combo:
                    if covered & cross_ones[idx]:
                        overlap = True
                        break
                    covered |= cross_ones[idx]
                if not overlap and covered == one_cells:
                    return [crosses[idx] for idx in combo]
        return []

    all_crosses = find_t_crosses_local(grid)
    crosses = find_non_overlapping(grid, all_crosses)

