# Proper L-shape corner detection
def find_l_shape_corner(cells):
    """Find the true corner of an L-shape (where two arms meet at 90°)"""
    cells_set = set(map(tuple, cells))
    for r, c in cells_set:
        neighbors = [(dr,dc) for dr,dc in [(-1,0),(1,0),(0,-1),(0,1)] if (r+dr,c+dc) in cells_set]
        if len(neighbors) == 2:
            (dr1, dc1), (dr2, dc2) = neighbors
            # Check if they're at 90° (not in same line)
            if not (dr1 == -dr2 and dc1 == -dc2):
                return (r, c), neighbors
    return None, None

